<template>
    <div class="study">
        <div class='flod study-flod' @click="flod"/>
        <div class='nav-bar' :style='{background: headBg}' v-show="isFlod">
            <!-- <p 
            v-for='(item, index) in routerData' :key='index'
            @click='goto(item, index)'
            :class='{active: flag === index}'>
            {{item.value}}
        </p> -->
            <div 
                style='position: fixed; top: -2px; right: 300px; z-index: 2020; height: 35px;
                 line-height: 35px; text-align: left; color: #FFF;width: 10%;'>
                <span>head-colors</span>
                <el-color-picker v-model="headBg" style='Opacity: 0;position: absolute; margin-left: -80px;'></el-color-picker>
            </div>
            <div 
                style='position: fixed; top: -2px; right: 180px; z-index: 2020; height: 35px; 
                line-height: 35px; text-align: left; color: #FFF;width: 10%;'>
                <span>body-colors</span>
                <el-color-picker v-model="bodyBg" style='Opacity: 0;position: absolute; margin-left: -80px;'></el-color-picker>
            </div>
            <ul>
                <li
                    v-for='(item, index) in routerData' :key='index'
                    @click='goto(item, index)'
                    @mouseover.stop='mouseover(item)'
                    @mouseleave='mouseout(item)'
                    :class='{active: flag === index, list: true}'>
                    {{item.value}}
                    <ul v-if='item.show'>
                        <li 
                            v-for='(child, num) in item.children' :key='num'
                            @click.stop='goto(child, index,item)'
                            :class='{"child-list": true}'>
                            {{child.value}}
                        </li>
                    </ul>
                </li>
            </ul>
        </div>
        <div class='router-space' :style='{background: bodyBg}' :class="{'router-space-active': isFlod}">
            <router-view/>
        </div>
    </div>
</template>
<script>
    // import _ from 'lodash';
    export default {
        data() {
            return {
                isFlod: false,
                headBg: '#29425B',
                bodyBg: 'rgba(0,0,0,.1)',
                flag: 0,
                routerData: [
                    {
                        path: '/study/first/first01',
                        value: 'firstBtn',
                        show: false,
                        children: [
                            {path: '/study/first/first01',value: 'first'},
                            {path: '/study/first/first02/1/2',value: 'second'},
                            {path: '/study/first/first03',value: 'third'},
                            {path: '/study/first/first04',value: 'fourth'},
                        ]
                    },
                    {
                        path: '/study/second/second01',
                        value: 'secondBtn',
                        show: false,
                        children: [
                            {path: '/study/second/second01',value: 'first'},
                            {path: '/study/second/second02',value: 'second'},
                            {path: '/study/second/second03',value: 'third'},
                            {path: '/study/second/second04',value: 'fourth'},
                        ]
                    },
                    {
                        path: '/study/third/third01',                      
                        value: 'thirdBtn',
                        show: false,
                        children: [
                            {path: '/study/third/third01',value: 'first'},
                            {path: '/study/third/third02',value: 'second'},
                            {path: '/study/third/third03',value: 'third'},
                            {path: '/study/third/third04',value: 'fourth'},
                        ]
                    },
                    {
                        path: '/study/fourth/fourth01',
                        value: 'fourthBtn',
                        show: false,
                        children: [
                            {path: '/study/fourth/fourth01',value: 'first'},
                            {path: '/study/fourth/fourth02',value: 'second'},
                            {path: '/study/fourth/fourth03',value: 'third'},
                            {path: '/study/fourth/fourth04',value: 'fourth'},
                        ]
                    },
                    // {path: '/changePage', value: 'changePage'},
                ]
            };
        },
        methods: {
            flod() {
                this.isFlod = !this.isFlod;
            },
            goto(data, index, item) {
                this.flag = index;
                this.$router.push(data.path);
                if(item) item.show = false;
               
            },
            mouseover(item) {
                item.show = true;
            },
            mouseout(item) {
                item.show = false;
            }
        },
        created(){
            // console.log(this._.chunk(['a', 'b', 'c', 'd'], 2), 'loadsh');
        }
    };
</script>
